INSERT INTO faq_data (intent, question, answer) VALUES
    ('nutrition', 'My child refuses vegetables. What can I do?', 'Offer vegetables in small portions and combine them with familiar foods. Keep the experience relaxed and avoid forcing.'),
    ('nutrition', 'What are simple healthy breakfast ideas for kids?', 'Try options like yogurt with fruit, whole-grain toast, or a boiled egg for a quick and balanced start.'),
    ('nutrition', 'How can I help my child drink more water?', 'Make water easily available and use fun cups or bottles to encourage regular drinking.'),
    ('nutrition', 'Is it okay if my child eats snacks every day?', 'Daily snacks are fine if they are healthy choices like fruit, yogurt, or nuts and eaten at consistent times.'),
    ('nutrition', 'What should I pack in a healthy lunchbox?', 'Include fruits, vegetables, protein like eggs or chicken, and whole grains for balance.'),
    ('nutrition', 'My child eats too much junk food. How can I reduce it?', 'Limit unhealthy options at home and replace them with healthier snacks that are easy to grab.'),
    ('nutrition', 'How can I make meals more interesting for my child?', 'Use colorful ingredients and creative presentation to make meals more appealing.'),
    ('nutrition', 'What is a balanced meal for children?', 'A balanced meal includes vegetables, protein, and carbohydrates in appropriate portions.'),
    ('nutrition', 'How do I deal with a child who skips meals?', 'Offer regular meal times and avoid replacing meals with snacks so hunger cues develop naturally.'),
    ('nutrition', 'Is milk important for children?', 'Milk can provide important nutrients, but it should be part of a balanced diet.'),
    ('nutrition', 'How can I reduce sugar intake in my child''s diet?', 'Avoid sugary drinks and choose natural foods like fruits instead of processed snacks.'),
    ('nutrition', 'My child only eats a few foods. Is that a problem?', 'It is common. Keep offering variety without pressure and allow gradual acceptance of new foods.'),
    ('nutrition', 'How can I encourage healthy eating habits early?', 'Model healthy eating and involve your child in food choices and preparation.'),
    ('nutrition', 'Are frozen foods okay for children?', 'Yes, as long as they are not highly processed and still provide nutritional value.'),
    ('nutrition', 'How can I manage portion sizes?', 'Serve small portions and allow children to ask for more if they are still hungry.'),
    ('nutrition', 'What are good alternatives to sugary snacks?', 'Try fruits, yogurt, nuts, or homemade snacks with less sugar.'),
    ('nutrition', 'My child eats too fast. What should I do?', 'Encourage slower eating by having relaxed family meals and limiting distractions.'),
    ('nutrition', 'Should children eat at the same time every day?', 'Regular meal times help establish healthy eating habits and routine.'),
    ('nutrition', 'How can I introduce new foods without resistance?', 'Introduce one new food at a time alongside familiar favorites.'),
    ('nutrition', 'What if my child refuses to try anything new?', 'Stay patient and continue offering new foods without pressure.'),
    ('nutrition', 'Are smoothies a healthy option?', 'Yes, smoothies with fruit, milk, and no added sugar can be a good option.'),
    ('nutrition', 'How do I handle picky eating at dinner?', 'Serve the same meal for everyone and include at least one familiar item.'),
    ('nutrition', 'Can children eat the same meals as adults?', 'Yes, with appropriate portion sizes and balanced ingredients.'),
    ('nutrition', 'How important is breakfast for children?', 'Breakfast helps provide energy and supports focus throughout the day.'),
    ('nutrition', 'What are quick after-school snacks?', 'Try fruit slices, yogurt, or whole-grain crackers.'),
    ('nutrition', 'How can I reduce processed food intake?', 'Prepare simple homemade meals and snacks when possible.'),
    ('nutrition', 'Is it okay for kids to skip vegetables sometimes?', 'Occasionally is fine, but keep offering vegetables regularly.'),
    ('nutrition', 'How can I make vegetables taste better?', 'Try different cooking methods like roasting or adding mild seasoning.'),
    ('nutrition', 'Should I reward my child for eating healthy food?', 'It is better to encourage naturally rather than using rewards.'),
    ('nutrition', 'What are healthy drink alternatives to juice?', 'Water and milk are the best choices for daily hydration.'),
    ('nutrition', 'How can I avoid mealtime conflicts?', 'Keep meals calm and avoid forcing or negotiating too much.'),
    ('nutrition', 'What if my child only wants snacks instead of meals?', 'Maintain structured meal times and limit grazing throughout the day.'),
    ('nutrition', 'How can I involve kids in healthy eating?', 'Let them help choose and prepare meals to increase engagement.'),
    ('nutrition', 'Are plant-based meals okay for kids?', 'Yes, if they include enough protein and nutrients.'),
    ('nutrition', 'What should I do if my child overeats?', 'Encourage awareness of fullness and avoid forcing them to finish everything.'),
    ('nutrition', 'How can I improve my child''s appetite?', 'Ensure regular activity and avoid excessive snacking before meals.'),
    ('nutrition', 'What is a good dinner routine?', 'Keep meals at consistent times and eat together as a family.'),
    ('nutrition', 'My kid will only eat white foods like bread and rice. What do I do?', 'Gradually introduce color by mixing small amounts of new foods into accepted ones and keep offering variety without pressure.'),
    ('nutrition', 'How do I get my toddler to eat more protein?', 'Try easy options like eggs, cheese, hummus, or small pieces of chicken that are simple to eat.'),
    ('nutrition', 'My child refuses to eat anything green. Any tips?', 'Try blending greens into sauces or smoothies so they are less visible, and keep offering them alongside preferred foods.'),
    ('nutrition', 'Is it bad if my child skips breakfast?', 'Breakfast supports energy and focus, so encourage a light option even if they are not very hungry in the morning.'),
    ('nutrition', 'How much fruit is too much for a child?', 'Two to three servings of whole fruit daily is generally fine, but limit fruit juice as it contains concentrated sugar.'),
    ('nutrition', 'My child loves chips and won''t eat real food', 'Reduce chips at home gradually and offer crunchy alternatives like rice cakes, cucumber slices, or lightly salted popcorn.'),
    ('nutrition', 'Should kids take vitamins?', 'A varied diet usually covers nutritional needs, but speak to your doctor if you are concerned about deficiencies.'),
    ('nutrition', 'How do I stop my child from eating too much sugar?', 'Swap sugary snacks for fruit, reduce sweet drinks, and avoid using sweets as rewards.'),
    ('nutrition', 'What foods help kids concentrate at school?', 'Whole grains, eggs, and fruit provide steady energy that supports focus throughout the school day.'),
    ('nutrition', 'My child is always hungry. Is that normal?', 'Growing children need frequent eating. Offer regular meals and healthy snacks to keep hunger satisfied.'),
    ('nutrition', 'How do I pack a lunch my child will actually eat?', 'Involve them in choosing what goes in, keep it simple, and include at least one food they really enjoy.'),
    ('nutrition', 'What is a good protein source for kids who don''t like meat?', 'Eggs, dairy, legumes, tofu, and nut butters are all good protein sources for children who avoid meat.'),
    ('nutrition', 'My child eats fine at school but refuses food at home', 'Try to keep meals relaxed at home and avoid making food a battleground. Peer influence often makes eating easier at school.'),
    ('nutrition', 'How can I limit my child''s fast food intake?', 'Cook simple meals at home more often and save fast food for occasional treats rather than regular meals.'),
    ('nutrition', 'Are eggs healthy for kids every day?', 'Eggs are nutritious and fine for most children daily as part of a varied diet.'),
    ('nutrition', 'My child drinks too much juice. How do I cut back?', 'Gradually dilute juice with water and offer plain water more often until juice becomes an occasional drink.'),
    ('nutrition', 'How do I get my child to eat more fibre?', 'Offer whole grain bread, fruits, vegetables, and legumes regularly to increase fibre naturally.'),
    ('nutrition', 'My child refuses to eat at the dinner table', 'Keep mealtimes calm and positive, remove distractions, and avoid forcing. Consistency helps over time.'),
    ('nutrition', 'What snacks are good for an active child?', 'Bananas, peanut butter on toast, yogurt, or trail mix provide good energy for active kids.'),
    ('nutrition', 'Is it okay for kids to be vegetarian?', 'Yes, a well-planned vegetarian diet can meet all a child''s nutritional needs with enough variety.'),
    ('nutrition', 'How can I make healthy food fun for kids?', 'Use cookie cutters for shapes, let them build their own plates, or name dishes in creative ways.'),
    ('nutrition', 'My child only wants to eat the same meal every day', 'This is common in young children. Keep offering variety alongside the accepted meal and introduce new foods slowly.'),
    ('nutrition', 'What are signs my child is not eating enough?', 'Low energy, poor growth, or frequent complaints of hunger may suggest their intake needs reviewing with a doctor.'),
    ('nutrition', 'How do I handle grandparents giving too many sweets?', 'Have a calm conversation about your family''s approach to food and suggest healthier treat alternatives.'),
    ('nutrition', 'Should children eat three meals or five smaller ones?', 'Either pattern can work. What matters most is that meals are balanced and regular.'),
    ('nutrition', 'My child refuses to try food if it looks different', 'Present new foods alongside familiar ones and avoid drawing too much attention to them. Repeated exposure helps.'),
    ('nutrition', 'Are rice and pasta okay for kids?', 'Yes, whole grain versions are a good source of energy and pair well with vegetables and protein.'),
    ('nutrition', 'How do I deal with a child who has strong food preferences?', 'Respect preferences while continuing to offer variety. Avoid creating a separate menu just for them.'),
    ('nutrition', 'What foods should I limit for young children?', 'Limit added sugar, excess salt, processed snacks, and sugary drinks which offer little nutritional value.'),
    ('nutrition', 'My child loves sweets but won''t eat savoury food', 'Avoid offering sweets before meals, keep savoury options visible, and don''t use sweets as a bargaining tool.'),
    ('nutrition', 'How do I help my child develop a healthy relationship with food?', 'Avoid labelling foods as good or bad, keep mealtimes positive, and let children learn to listen to their hunger.'),
    ('nutrition', 'Is cheese a healthy snack for kids?', 'Yes, cheese provides calcium and protein and is a convenient and nutritious snack in moderate amounts.'),
    ('nutrition', 'How do I stop my child from eating out of boredom?', 'Offer regular meals and structured snack times, and redirect boredom eating with activities or drinks of water.'),
    ('nutrition', 'My child only eats plain food with no sauces or mixing', 'That is okay. Serve components separately and continue offering combination dishes without pressure.'),
    ('nutrition', 'What is a good after-school snack to tide over until dinner?', 'Something light like fruit, crackers with cheese, or yogurt keeps energy up without spoiling appetite for dinner.'),
    ('nutrition', 'How do I make sure my child gets enough iron?', 'Include iron-rich foods like red meat, beans, leafy greens, and fortified cereals in their diet regularly.'),
    ('nutrition', 'My child throws food they don''t like. How do I respond?', 'Stay calm, remove the food without reaction, and continue offering variety at the next meal.'),
    ('activity', 'My child does not enjoy sports. What can I do?', 'Focus on fun activities like games or dancing instead of structured sports.'),
    ('activity', 'How can I encourage daily movement?', 'Include short active breaks throughout the day such as walking or stretching.'),
    ('activity', 'What are simple indoor activities for kids?', 'Try dancing, jumping games, or simple exercises at home.'),
    ('activity', 'How much activity is enough for children?', 'Children should aim for around 60 minutes of activity daily.'),
    ('activity', 'How do I make exercise enjoyable?', 'Turn activities into games and join them to make it social and fun.'),
    ('activity', 'What are good outdoor activities?', 'Playing at parks, cycling, or simple ball games are great options.'),
    ('activity', 'How can I reduce sedentary time?', 'Encourage movement breaks and limit long periods of sitting.'),
    ('activity', 'My child prefers staying indoors. What can I do?', 'Start with indoor activities and gradually introduce outdoor options.'),
    ('activity', 'Are short activities effective?', 'Yes, even short bursts of activity throughout the day are beneficial.'),
    ('activity', 'How can I build active habits?', 'Schedule daily active time and keep it consistent.'),
    ('activity', 'Is family activity important?', 'Yes, it encourages participation and strengthens relationships.'),
    ('activity', 'How can I motivate inactive children?', 'Find activities they enjoy instead of forcing structured exercise.'),
    ('activity', 'What activities improve coordination?', 'Games like catching, throwing, or balancing help build coordination.'),
    ('activity', 'How can I include activity in daily routines?', 'Walk to school, take stairs, or play after meals.'),
    ('activity', 'What are low-effort activities?', 'Walking, stretching, or simple play are easy options.'),
    ('activity', 'How do I get my child off the couch?', 'Suggest a short walk or active game together rather than telling them to exercise.'),
    ('activity', 'My child says exercise is boring', 'Try variety and let them choose the activity so it feels like play rather than exercise.'),
    ('activity', 'What indoor games get kids moving?', 'Hide and seek, obstacle courses, dancing, or balloon games are great for indoor movement.'),
    ('activity', 'How do I exercise with my child?', 'Join them in walks, bike rides, or backyard games so it becomes shared family time.'),
    ('activity', 'My child is very shy and won''t join group sports', 'Start with individual activities like cycling or swimming before gradually introducing group settings.'),
    ('activity', 'Are team sports good for kids?', 'Team sports build social skills and coordination, but only if the child enjoys them. Non-competitive options work too.'),
    ('activity', 'How do I keep my child active in winter?', 'Try indoor activities like dancing, yoga, or active video games when outdoor options are limited.'),
    ('activity', 'What activities are good for younger children?', 'Running, jumping, climbing, and unstructured outdoor play are ideal for younger children.'),
    ('activity', 'How can I make walking more fun for kids?', 'Turn it into a game like spotting shapes or colours, or explore a new route together.'),
    ('activity', 'Is swimming good exercise for children?', 'Swimming builds strength, coordination, and endurance and is an excellent all-round activity for kids.'),
    ('activity', 'My child is overweight and reluctant to exercise', 'Focus on enjoyable movement rather than weight, and avoid making exercise feel like a punishment.'),
    ('activity', 'How do I balance structured sports and free play?', 'Both have value. Aim for a mix so children develop skills and also enjoy unstructured movement.'),
    ('activity', 'What if my child quits every sport they try?', 'Let them explore different activities without pressure. Finding the right fit takes time.'),
    ('activity', 'Are video games that involve movement okay?', 'Active games that get kids moving are better than passive sitting, but still combine with outdoor activity.'),
    ('activity', 'How much outdoor play does a child need?', 'Aim for at least some outdoor time each day for fresh air, movement, and unstructured exploration.'),
    ('activity', 'How do I encourage my teenager to be more active?', 'Respect their interests and suggest activities they find appealing rather than enforcing structured exercise.'),
    ('activity', 'My child gets tired very quickly during exercise', 'Gradual increase in activity is normal. Build stamina slowly with consistent, enjoyable movement.'),
    ('activity', 'What are signs my child is not active enough?', 'Frequent fatigue, low energy, or poor mood may suggest they need more regular physical activity.'),
    ('activity', 'Can kids exercise every day?', 'Yes, daily movement is encouraged as long as it is varied, enjoyable, and not overly intense.'),
    ('activity', 'My child only wants to play on devices instead of moving', 'Limit device time and offer engaging physical alternatives that compete with screen appeal.'),
    ('activity', 'How do I make PE homework less of a battle?', 'Do it together, keep it brief, and frame it as something fun rather than a school task.'),
    ('activity', 'What activities can we do as a family on weekends?', 'Hikes, bike rides, swimming, or backyard games are easy ways to stay active together.'),
    ('activity', 'Is yoga suitable for children?', 'Yes, child-friendly yoga improves flexibility, focus, and calm and can be done at any fitness level.'),
    ('activity', 'How do I help my child enjoy physical activity long term?', 'Let them lead their choices, keep it fun, and celebrate effort rather than performance.'),
    ('activity', 'What is the best time of day for kids to exercise?', 'After school or late afternoon tends to work well, but any time that fits your routine is fine.'),
    ('activity', 'My child hates running. What else can they do?', 'Running is just one option. Swimming, cycling, dancing, or martial arts provide similar fitness benefits.'),
    ('activity', 'How do I help a child who is not naturally sporty?', 'Focus on movement rather than performance and try creative or artistic physical activities like dance.'),
    ('activity', 'Can children exercise too much?', 'Excessive intense training can strain young bodies. Balance activity with rest and avoid over-scheduling sports.'),
    ('activity', 'How do I know if my child is getting enough physical activity?', 'If they have good energy, sleep well, and move freely in daily life, they are likely active enough.'),
    ('activity', 'What are fun rainy day activities that involve movement?', 'Indoor obstacle courses, dance parties, yoga videos, or active games keep kids moving on rainy days.'),
    ('activity', 'My child refuses to go outside', 'Start by going outside together for short periods with no agenda and let curiosity take over naturally.'),
    ('activity', 'How do I create an active lifestyle for my family?', 'Build movement into everyday routines like walking, cycling to school, or evening walks together.'),
    ('activity', 'Are martial arts a good activity for children?', 'Martial arts build discipline, coordination, and confidence and are suitable for a wide range of children.'),
    ('activity', 'How do I keep my child motivated to stay active?', 'Celebrate consistency, let them choose activities, and keep the focus on fun rather than results.'),
    ('activity', 'How do I encourage a child who is embarrassed about their fitness level?', 'Focus on personal progress rather than comparison and choose activities where they can build confidence gradually.'),
    ('activity', 'What if my child loves screens and nothing else?', 'Introduce activity in small steps and connect it to their interests, such as gaming-themed active challenges.'),
    ('activity', 'How do I help my child be active without it feeling like exercise?', 'Frame movement as play, adventure, or exploration and avoid using the word exercise with younger children.'),
    ('activity', 'My child is very competitive and gets upset when they lose', 'Choose cooperative activities over competitive ones and help them learn that effort matters more than winning.'),
    ('activity', 'How do I encourage a sedentary child to move more?', 'Start with tiny amounts of movement daily and gradually build up as they become more comfortable being active.'),
    ('activity', 'What are good activities for kids with limited outdoor space?', 'Jump rope, hopscotch, or simple movement games in a small yard or hallway can provide enough activity indoors.'),
    ('activity', 'How do I make physical activity a family value?', 'Talk positively about moving, prioritise active family time, and show your own enjoyment of physical activity.'),
    ('screen', 'How much screen time is appropriate?', 'Follow general guidelines of one to two hours of recreational screen time per day for school-aged children.'),
    ('screen', 'My child throws tantrums when screens are taken away', 'Give warnings before ending screen time and keep limits consistent so expectations are clear.'),
    ('screen', 'Should I allow screens before bedtime?', 'Avoid screens for at least an hour before bed as they can disrupt sleep.'),
    ('screen', 'How can I set screen time limits?', 'Create a clear daily schedule for when screens are allowed and stick to it consistently.'),
    ('screen', 'My child watches YouTube for hours. How do I stop this?', 'Set a daily time limit, use a timer they can see, and have an engaging activity ready for when time is up.'),
    ('screen', 'Are educational apps worth the screen time?', 'Educational apps have value but should be time-limited and balanced with offline learning and play.'),
    ('screen', 'How can I reduce gaming time?', 'Set time limits and encourage alternative hobbies.'),
    ('screen', 'What if my child refuses to stop using devices?', 'Give warnings before stopping and stick to limits.'),
    ('screen', 'How can I avoid screen dependence?', 'Encourage varied activities and limit passive screen use.'),
    ('screen', 'How do I manage screen use after school?', 'Allow limited screen time after homework or activity.'),
    ('screen', 'Can screen time affect behavior?', 'Too much screen time may impact mood and focus.'),
    ('screen', 'How can I encourage better screen habits?', 'Set routines and provide engaging alternatives.'),
    ('screen', 'What is a good screen-time balance?', 'Combine screen use with physical and social activities.'),
    ('screen', 'How do I transition away from screens?', 'Use gradual reduction and introduce other fun activities.'),
    ('screen', 'Are tablets better than phones?', 'The type matters less than how long and how they are used.'),
    ('screen', 'How do I manage multiple devices?', 'Apply consistent rules across all devices.'),
    ('screen', 'How can I make screen limits easier?', 'Use routines so children know when screens are allowed.'),
    ('screen', 'Should I use parental controls?', 'They can help manage usage but should be combined with guidance.'),
    ('screen', 'How can I reduce screen use before bedtime?', 'Introduce calming activities like reading instead.'),
    ('screen', 'How do I balance school and screen use?', 'Prioritize homework and limit recreational screen time.'),
    ('screen', 'What if screens are part of schoolwork?', 'Separate learning use from entertainment use.'),
    ('screen', 'How can I keep children engaged without screens?', 'Offer creative or active play options.'),
    ('screen', 'How can I prevent overuse of digital devices?', 'Set clear limits and encourage breaks.'),
    ('screen', 'My child is addicted to gaming. What should I do?', 'Set firm daily time limits, encourage other hobbies, and avoid using games as a reward or threat.'),
    ('screen', 'How do I know if screen time is too much?', 'Watch for signs like irritability after use, neglected activities, or poor sleep which suggest overuse.'),
    ('screen', 'Should children have their own devices?', 'Consider their maturity and your ability to monitor use before giving children their own devices.'),
    ('screen', 'How do I create a family screen time agreement?', 'Involve children in setting rules so they feel ownership and are more likely to follow them.'),
    ('screen', 'My child sneaks devices at night', 'Keep devices out of bedrooms at night and charge them in a shared family space.'),
    ('screen', 'Can too much screen time affect eyesight?', 'Prolonged screen use can cause eye strain. Encourage regular breaks and outdoor time to reduce eye fatigue.'),
    ('screen', 'How do I explain screen time limits to young children?', 'Use simple language, be consistent, and frame limits as a routine rather than a punishment.'),
    ('screen', 'Is it okay for kids to watch TV during meals?', 'Mealtime screens reduce family conversation and mindful eating. It is better to keep meals screen-free.'),
    ('screen', 'What are the benefits of limiting screen time?', 'Less screen time is linked to better sleep, more physical activity, and stronger social skills.'),
    ('screen', 'My child only wants to play Roblox all day', 'Set clear daily time limits for gaming and have offline activities they enjoy ready as alternatives.'),
    ('screen', 'How do I deal with screen time battles every day?', 'Consistent rules and predictable schedules reduce daily arguments. Engage children in setting the limits.'),
    ('screen', 'Should I monitor what my child watches online?', 'Yes, especially for younger children. Use parental controls and have open conversations about online safety.'),
    ('screen', 'How do I help my child use screens more mindfully?', 'Encourage them to pause and ask if they are enjoying what they are watching rather than watching out of habit.'),
    ('screen', 'Is it okay for toddlers to have screen time?', 'Minimal screen time is recommended for very young children, with preference for interactive and educational content.'),
    ('screen', 'How can I replace screen time with other activities?', 'Keep a list of engaging offline alternatives handy so there is always something to do when screens are off.'),
    ('screen', 'My child watches inappropriate content online', 'Review and activate parental controls, have an honest age-appropriate conversation, and revisit online safety rules.'),
    ('screen', 'How do I handle screen time during school holidays?', 'Set a holiday screen schedule in advance that balances free time with active and creative activities.'),
    ('screen', 'Does screen time affect children''s sleep?', 'Yes, especially screens before bed. The light and stimulation can delay sleep onset and reduce sleep quality.'),
    ('screen', 'My child uses devices to avoid social situations', 'Gently encourage social activity and look for whether anxiety or discomfort is driving the avoidance.'),
    ('screen', 'How early should I start setting screen rules?', 'Introduce simple screen boundaries early so they become a normal part of your child''s expectations.'),
    ('screen', 'What should I do when screen time rules are broken?', 'Apply consistent consequences calmly and revisit the rules together to reinforce understanding.'),
    ('screen', 'How do I stop my child comparing screen time with friends?', 'Acknowledge the difference calmly and explain that different families have different rules.'),
    ('screen', 'Can screens be used as a reward?', 'Using screens as a reward can increase their perceived value. It is better to keep them as a neutral daily activity.'),
    ('screen', 'What are signs my child is spending too much time on screens?', 'Irritability when devices are taken away, neglecting friends, poor sleep, or losing interest in other activities are warning signs.'),
    ('screen', 'How do I manage screen time for multiple children with different needs?', 'Set fair family-wide rules while allowing small adjustments for age or homework requirements.'),
    ('screen', 'My teenager says all their friends have no limits on screens', 'Acknowledge their frustration and explain your reasoning calmly. Peer comparison is normal but not a reason to abandon boundaries.'),
    ('screen', 'How do I talk to my child about online safety?', 'Use age-appropriate language, keep the conversation open and ongoing, and focus on staying safe rather than creating fear.'),
    ('screen', 'My child gets angry every time I turn off the TV', 'Use a visible countdown timer so they can prepare for the transition and the ending never feels sudden.'),
    ('screen', 'Is it okay for children to use screens for creative activities?', 'Creative uses like drawing apps or making videos have more value than passive watching, but time limits still apply.'),
    ('screen', 'How do I reduce my own screen use as a role model?', 'Be mindful of your own habits and model the boundaries you want your children to follow.'),
    ('screen', 'My child has no interest in anything except screens', 'Gradually introduce offline activities one at a time and be patient as interests develop alongside reduced screen time.'),
    ('screen', 'What screen-free activities can replace device time?', 'Drawing, building, reading, cooking together, or outdoor play are all engaging alternatives to screen time.'),
    ('screen', 'Should I limit screen time on weekends too?', 'Yes, consistent limits across the week are more effective than strict weekdays followed by unrestricted weekends.'),
    ('screen', 'How do I introduce screen-free days?', 'Start with one screen-free afternoon per week and fill it with enjoyable activities so it feels positive rather than restrictive.'),
    ('routine', 'How can I build a daily routine for my child?', 'Create a simple schedule including meals, activity, and sleep.'),
    ('routine', 'What is a good bedtime routine?', 'Include calming activities like reading and keep a consistent time.'),
    ('routine', 'Why are routines important?', 'Routines provide structure and help children feel secure.'),
    ('routine', 'How can I improve morning routines?', 'Prepare things the night before and keep mornings simple.'),
    ('routine', 'How do I manage irregular schedules?', 'Keep key routines like meals and sleep consistent.'),
    ('routine', 'How can I help my child sleep better?', 'Maintain consistent sleep times and reduce screen use before bed.'),
    ('routine', 'What if my child resists bedtime?', 'Use calming routines and stay consistent.'),
    ('routine', 'How do routines affect behavior?', 'Consistent routines can improve mood and reduce stress.'),
    ('routine', 'How can I include homework in routine?', 'Set a regular time each day in a quiet space.'),
    ('routine', 'How flexible should routines be?', 'Keep routines consistent but allow some flexibility.'),
    ('routine', 'How can I start a new routine?', 'Introduce changes gradually and keep expectations simple.'),
    ('routine', 'How do I maintain routines long term?', 'Keep them simple so they become habits.'),
    ('routine', 'How can I manage after-school time?', 'Balance homework, activity, and rest time.'),
    ('routine', 'What is a healthy evening routine?', 'Include dinner, relaxation, and preparation for bedtime.'),
    ('routine', 'How can I improve time management?', 'Use simple schedules and consistent daily patterns.'),
    ('routine', 'How do I reduce daily chaos?', 'Stick to predictable routines and plan ahead.'),
    ('routine', 'What if routines keep changing?', 'Focus on keeping core habits consistent.'),
    ('routine', 'How can I teach responsibility through routine?', 'Assign simple daily tasks as part of the routine.'),
    ('routine', 'How can I help children follow routines?', 'Use reminders and keep routines easy to follow.'),
    ('routine', 'How do I make routines enjoyable?', 'Keep them simple and include positive interactions.'),
    ('routine', 'How can I balance routine and flexibility?', 'Maintain structure but allow occasional changes.'),
    ('routine', 'What if my child ignores routines?', 'Be consistent and reinforce expectations calmly.'),
    ('routine', 'How do routines help sleep?', 'Consistent bedtime routines support better sleep patterns.'),
    ('routine', 'How can I manage weekend routines?', 'Keep similar sleep and meal times with slight flexibility.'),
    ('routine', 'How do I transition between activities?', 'Give advance notice and keep transitions smooth.'),
    ('routine', 'How can I reduce stress with routines?', 'Predictable schedules reduce uncertainty and stress.'),
    ('routine', 'How do I adapt routines as children grow?', 'Adjust schedules gradually based on their needs.'),
    ('routine', 'What is a simple daily structure?', 'Meals, learning time, activity, and rest.'),
    ('routine', 'How can I keep routines consistent?', 'Follow similar timing every day.'),
    ('routine', 'How can I make routines easier to follow?', 'Keep them short and clear.'),
    ('routine', 'What if my child gets bored with routine?', 'Add small variations while keeping structure.'),
    ('routine', 'How do routines improve independence?', 'Children learn to manage tasks on their own.'),
    ('routine', 'How can I build healthy habits through routine?', 'Repeat simple behaviors daily until they become habits.'),
    ('routine', 'How can I encourage consistency?', 'Use simple rules and positive reinforcement.'),
    ('routine', 'What if routines feel too strict?', 'Adjust them to be more flexible and realistic.'),
    ('routine', 'My child won''t go to sleep at bedtime', 'Keep the bedtime routine calm, consistent, and predictable so their body learns to wind down at the same time each night.'),
    ('routine', 'How do I get my child up in the morning without a battle?', 'Prepare clothes and bags the night before and use a gentle alarm or gradual wake-up routine to ease mornings.'),
    ('routine', 'My child stalls at bedtime with endless requests', 'Anticipate common requests like a drink or toilet visit within the routine so there is less room to delay.'),
    ('routine', 'How do I create a homework routine that actually works?', 'Set a consistent time and quiet location shortly after school so homework becomes an expected part of the day.'),
    ('routine', 'My child can''t wind down before bed', 'Introduce calming activities like reading, gentle stretching, or soft music in the hour before bedtime.'),
    ('routine', 'What is a good after-school routine?', 'Snack, some downtime, homework, then free play or activity works well for most school-aged children.'),
    ('routine', 'How long should a bedtime routine take?', 'Aim for 20 to 30 minutes for a bedtime routine so it is calming but not drawn out.'),
    ('routine', 'My child wakes up early and disturbs everyone', 'Set a visual clock to show when it is okay to get up and keep mornings calm so early waking is less disruptive.'),
    ('routine', 'How do I handle routine disruptions during holidays?', 'Relax some rules but keep sleep and meal times roughly consistent to avoid adjustment difficulties when school resumes.'),
    ('routine', 'Should children have the same bedtime every night?', 'A consistent bedtime within about 30 minutes each night supports better sleep quality and easier mornings.'),
    ('routine', 'How do I help my child adjust to a new school schedule?', 'Practise the new timing before school starts and build in extra buffer time until the routine feels natural.'),
    ('routine', 'My child rushes through their routine and makes mistakes', 'Build in slightly more time and walk through steps together until the routine becomes more automatic.'),
    ('routine', 'How do I get my child to brush their teeth without a fight?', 'Make it part of a consistent bedtime routine and use a fun timer or favourite song to make it feel less like a chore.'),
    ('routine', 'What if my child''s routine keeps getting disrupted by activities?', 'Treat extracurriculars as part of the routine and adjust the schedule around them rather than abandoning structure.'),
    ('routine', 'How do I establish a reading routine?', 'Set aside a regular reading time each day, even just ten minutes, and make it a relaxed and enjoyable habit.'),
    ('routine', 'My child has trouble remembering steps in their routine', 'Use a simple visual checklist on the wall to help them track each step independently.'),
    ('routine', 'How early should children have a bedtime routine?', 'Starting a consistent bedtime routine from infancy helps establish healthy sleep habits that carry through childhood.'),
    ('routine', 'How do I handle two children with different bedtime needs?', 'Stagger bedtimes based on age and give each child their own brief routine so both feel the process is fair.'),
    ('routine', 'What should a morning routine include?', 'Getting dressed, eating breakfast, brushing teeth, and packing bags are the core elements of a functional morning routine.'),
    ('routine', 'How do I make routines work for a child with high energy?', 'Include active elements in the routine and schedule movement before quieter tasks like homework or bedtime wind-down.'),
    ('routine', 'My child''s routine falls apart at weekends', 'Keep sleep and meal times close to weekday times on weekends to prevent a full reset of the week''s progress.'),
    ('routine', 'How can I use routine to reduce mealtime stress?', 'Regular meal times at the same place each day reduce uncertainty and make children more likely to eat without fuss.'),
    ('routine', 'How do I help my child transition from play to routine tasks?', 'Give a five-minute warning before transitions and use a consistent signal like a timer or phrase to cue the change.'),
    ('routine', 'What if my child refuses to follow the routine?', 'Stay calm, offer limited choices within the routine, and avoid power struggles. Consistency over time usually wins.'),
    ('routine', 'How do I build a routine for a child with lots of after-school activities?', 'Map out the week visually so your child can see what happens each day and when downtime and rest are built in.'),
    ('routine', 'My child sleeps too late and is hard to wake for school', 'Gradually shift bedtime earlier by 15 minutes every few days until the wake time feels manageable.'),
    ('routine', 'How can I involve my child in creating their routine?', 'Let them help decide the order of tasks and when breaks happen so they feel invested in following it.'),
    ('routine', 'What are signs that a routine is working?', 'Fewer morning battles, smoother transitions, better sleep, and a calmer overall mood suggest a routine is effective.'),
    ('routine', 'How do I adjust a routine when life gets busy?', 'Simplify the routine to its essentials during busy periods and restore the full structure when things settle.'),
    ('routine', 'My child has anxiety about changes to the routine', 'Prepare them in advance for any changes and explain what will be different so the adjustment feels less abrupt.'),
    ('routine', 'How do routines support emotional regulation in children?', 'Predictable routines reduce anxiety by giving children a sense of control and knowing what to expect each day.'),
    ('routine', 'How do I restart a routine that has broken down?', 'Start fresh with just two or three key anchor points like wake time, meals, and bedtime and build from there.'),
    ('routine', 'What if my partner and I have different approaches to routine?', 'Agree on the most important elements and try to present a consistent approach so children receive clear signals.'),
    ('routine', 'How do I use a visual schedule with young children?', 'Use pictures or simple drawings to represent each part of the day so young children can follow the routine independently.'),
    ('routine', 'My child does better with structure but resists being told what to do', 'Give them predictability through routine while offering small choices within it so they feel some control.'),
    ('routine', 'How do I build a relaxing bedtime routine for an anxious child?', 'Use calm, repetitive steps like bath, story, and quiet talk to signal safety and help them wind down gently.'),
    ('routine', 'What is the best way to handle missed routine steps?', 'Skip the missed step calmly without drama and continue with the rest of the routine as normal.'),
    ('routine', 'How do I help my child manage time independently?', 'Teach them to use a simple clock or timer and practise estimating how long tasks take within the routine.'),
    ('routine', 'My child needs a lot of reminders to follow their routine', 'Use visual cues, timers, or a checklist rather than verbal reminders to build independence over time.'),
    ('routine', 'How do I make bedtime less of a struggle every night?', 'Keep the routine short, calm, and consistent and avoid engaging with stalling tactics so the process becomes predictable.'),
    ('routine', 'What if my child''s routine needs to change due to a new school year?', 'Introduce the new schedule gradually before the change happens and involve your child in planning the new routine.'),
    ('nutrition', 'How do I get my child to eat more calcium-rich foods?', 'Include dairy products, fortified plant milks, leafy greens, and cheese regularly to support bone health.'),
    ('activity', 'How do I encourage my child to try a new sport?', 'Let them watch a session first before committing and make the first try low-pressure and fun.'),
    ('activity', 'What are good activities for children who prefer solo play?', 'Cycling, swimming, gymnastics, or individual martial arts suit children who prefer working on their own pace.'),
    ('activity', 'How do I help my child stay active during exams?', 'Short movement breaks during study sessions improve focus and reduce stress without taking much time.'),
    ('activity', 'My child complains of aches after activity. What should I do?', 'Light soreness after exercise is normal, but persistent pain should be checked by a doctor to rule out injury.'),
    ('activity', 'How do I get my child interested in being active when they prefer reading?', 'Try audiobooks during walks or combine their interests with gentle movement to make activity feel natural.'),
    ('activity', 'What is the difference between play and structured exercise for kids?', 'Both are valuable. Free play builds creativity and coordination while structured activity develops specific skills.'),
    ('activity', 'How do I balance activity with enough rest for my child?', 'Alternate active days with lighter ones and ensure children have downtime to recover and recharge.'),
    ('activity', 'My child is active at school but sedentary at home', 'That is a good sign. Add some gentle evening movement like a walk or stretch to round out the day.'),
    ('activity', 'How do I help my child enjoy exercise despite low self-confidence?', 'Choose activities where success comes quickly, celebrate small wins, and avoid comparing them to others.'),
    ('activity', 'What are simple stretches children can do daily?', 'Arm circles, toe touches, and gentle neck rolls are easy stretches children can do before or after activity.'),
    ('activity', 'How do I handle a child who is afraid of trying physical activities?', 'Start with familiar movements in a safe environment and build confidence gradually through positive experiences.'),
    ('activity', 'Can children do strength training?', 'Bodyweight exercises like jumping, climbing, and push-ups are appropriate for children and build strength safely.'),
    ('activity', 'How do I keep my child active when we travel?', 'Walk to explore new places, use hotel pools, or play simple games in open spaces to stay active while travelling.'),
    ('activity', 'What role does unstructured play have in a child''s development?', 'Unstructured play builds creativity, problem-solving, and social skills alongside physical fitness.'),
    ('activity', 'How do I introduce my child to a love of nature through activity?', 'Take short nature walks, explore local parks, or do simple gardening together to connect movement with the outdoors.'),
    ('activity', 'My child only likes screen-based activity games', 'Active games are a starting point. Gradually introduce real-world versions of the same movements to expand their activity.'),
    ('activity', 'How do I deal with a child who always finds excuses not to exercise?', 'Reduce barriers by having gear ready, keeping sessions short, and making the activity genuinely enjoyable.'),
    ('activity', 'What are good after-dinner activities for families?', 'A short walk, backyard games, or a gentle bike ride after dinner is a healthy way to end the day together.'),
    ('screen', 'How do I handle my child lying about screen time?', 'Keep devices in shared spaces, use parental controls, and have honest conversations about why limits exist.'),
    ('screen', 'Should I have screen-free zones in the house?', 'Yes, bedrooms and dining areas work well as screen-free zones to support sleep and family connection.'),
    ('screen', 'My child says they are bored without screens', 'Boredom is healthy and encourages creativity. Have a list of offline activities ready for when screens are off.'),
    ('screen', 'How do I manage screen time when my child uses it for socialising?', 'Acknowledge the social value while still maintaining reasonable time limits and encouraging in-person interaction.'),
    ('screen', 'Is it okay for children to watch movies on weekends?', 'Occasional longer viewing on weekends is fine if it is balanced with physical activity and family time.'),
    ('screen', 'How do I stop screens from replacing outdoor play?', 'Set outdoor time as a daily expectation before screens are available so movement comes first.'),
    ('screen', 'My child uses screens to cope with difficult emotions', 'Acknowledge their feelings and gently introduce other coping strategies like talking, drawing, or physical activity.'),
    ('screen', 'What should I do if my child watches violent content online?', 'Stay calm, use it as an opportunity to discuss what they saw, and review your parental control settings together.'),
    ('screen', 'How do I limit screen time without feeling like the bad parent?', 'Frame limits as caring for their health and wellbeing and stay confident that boundaries are part of good parenting.'),
    ('screen', 'Are there any benefits to some screen time?', 'Screens can support learning, creativity, and social connection when used intentionally and in moderation.'),
    ('screen', 'How do I reduce my child''s screen time without taking it away completely?', 'Set gradual reductions over several weeks rather than sudden removal so the adjustment feels manageable.'),
    ('screen', 'My child gets headaches after screen use', 'Encourage regular screen breaks using the 20-20-20 rule and reduce overall daily screen time.'),
    ('screen', 'How do I keep screen time rules in place when other caregivers are less strict?', 'Communicate your approach clearly to all caregivers and ask for consistency to avoid confusing your child.'),
    ('screen', 'What is the 20-20-20 rule for screen use?', 'Every 20 minutes, look at something 20 feet away for 20 seconds to reduce eye strain during screen use.'),
    ('screen', 'How do I talk to my child about social media pressure?', 'Keep conversations open and non-judgmental, listen to their experiences, and discuss healthy online boundaries together.'),
    ('screen', 'My child is upset when peers discuss content I have restricted', 'Validate their frustration and explain your reasons calmly. Being left out can feel hard but limits are still appropriate.'),
    ('screen', 'How do I make screen-free time feel like a reward not a punishment?', 'Fill screen-free time with enjoyable activities so children associate it with fun rather than deprivation.'),
    ('screen', 'How do I set limits on streaming services?', 'Use the platform''s built-in parental controls to set daily viewing limits and restrict inappropriate content.');